package com.google.gson.internal;

import static org.mockito.Mockito.*;

import com.google.gson.JsonElement;
import com.google.gson.internal.bind.TypeAdapter;
import com.google.gson.internal.bind.TypeAdapters;
import com.google.gson.stream.JsonWriter;
import java.io.IOException;
import org.junit.jupiter.api.Test;
import org.mockito.MockedStatic;
import org.mockito.Mockito;

class StreamsTest {

  @Test
  void write_callsTypeAdaptersJsonElementWrite() throws IOException {
    JsonElement element = mock(JsonElement.class);
    JsonWriter writer = mock(JsonWriter.class);

    try (MockedStatic<TypeAdapters> mockedTypeAdapters = Mockito.mockStatic(TypeAdapters.class)) {
      @SuppressWarnings("unchecked")
      TypeAdapter<JsonElement> jsonElementAdapterMock = mock(TypeAdapter.class);

      // Use doReturn for static field mocking instead of lambda returning a field
      mockedTypeAdapters.when(() -> TypeAdapters.JSON_ELEMENT).thenReturn(jsonElementAdapterMock);

      doNothing().when(jsonElementAdapterMock).write(writer, element);

      Streams.write(element, writer);

      verify(jsonElementAdapterMock).write(writer, element);
    }
  }
}
